/**
 * Notification model and core types for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. Services emit
 * domain events (order:created, user:updated, etc.) and the NotificationService
 * listens, creates NotificationPayloads, and dispatches them through
 * NotificationAdapter implementations (email, webhook, in-app, etc.).
 *
 * Constraints:
 * - All notification delivery MUST go through a NotificationAdapter.
 * - All adapters MUST implement the NotificationAdapter interface.
 * - All triggers MUST originate from EventBus events — no direct calls.
 * - NotificationType defines the set of supported notification categories.
 * - NotificationChannel defines the delivery mechanism.
 */

/**
 * Supported notification categories. Extend this union as new
 * notification types are needed.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/**
 * Delivery channels. Each channel corresponds to a NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook';

/**
 * The payload passed to adapters for delivery.
 */
export interface NotificationPayload {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  createdAt: Date;
}

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  notificationId: string;
  channel: NotificationChannel;
  error?: string;
}

/**
 * Stored notification record with delivery status.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  status: 'pending' | 'sent' | 'failed';
  sentAt: Date;
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * adapters must implement.
 *
 * Architecture constraint: Every delivery channel (email, webhook, in-app,
 * SMS, push, etc.) MUST implement this interface and be registered with
 * the NotificationService. The NotificationService routes payloads to
 * adapters based on the payload's `channel` field.
 *
 * To add a new delivery channel:
 * 1. Add the channel name to NotificationChannel in models/notification.ts
 * 2. Create an adapter class implementing this interface
 * 3. Register the adapter with NotificationService.registerAdapter()
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /**
   * The channel this adapter handles. Must match a NotificationChannel value.
   */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must return a result indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends rather than
 * connecting to a real SMTP/email service. Replace the send() body
 * with real email delivery (e.g., SendGrid, SES, nodemailer) when ready.
 *
 * Implements the NotificationAdapter interface as required by the
 * notification system architecture.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  from: string;
  replyTo?: string;
}

const defaultEmailConfig: EmailConfig = {
  from: 'noreply@taskflowpro.com',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: NotificationPayload[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: ${payload.subject}`,
    );

    // Validate recipient looks like an email
    if (!payload.recipient.includes('@')) {
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    // Stub: store in memory instead of sending a real email.
    // Replace this block with actual email provider integration.
    this.sentEmails.push(payload);

    this.logger.info(
      `Email sent: ${payload.id} from ${this.config.from} to ${payload.recipient}`,
    );

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
    };
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

